// The input is an array with a single object containing the FOG API response
const fogResponse = items[0].json;

// Check if we have a successful response
if (!fogResponse.success || !fogResponse.data || !fogResponse.data.hosts) {
  console.log('Invalid FOG response structure');
  return [];
}

// Get the hosts array from the response
const hosts = fogResponse.data.hosts;

// Filter hosts that have inventory data
const hostsWithInventory = hosts.filter(host => {
  // Check if inventory exists
  if (!host.inventory) {
    console.log(`Host ${host.name || host.id} has no inventory object`);
    return false;
  }

  // Check if inventory has any data
  const inventory = host.inventory;
  const hasInventoryData = Object.keys(inventory).length > 0;

  if (!hasInventoryData) {
    console.log(`Host ${host.name || host.id} has empty inventory object`);
    return false;
  }

  // Check for valid serial number
  const serial = inventory.sysserial;
  if (!serial || 
      serial === 'System Serial Number' || 
      serial === 'To be filled by O.E.M.' ||
      serial === 'Default string') {
    console.log(`Host ${host.name || host.id} has invalid serial: ${serial}`);
    return false;
  }

  console.log(`Host ${host.name || host.id} has valid inventory with serial: ${serial}`);
  return true;
});

console.log(`=== Filter Results ===`);
console.log(`Total hosts: ${hosts.length}`);
console.log(`Hosts with valid inventory: ${hostsWithInventory.length}`);
console.log(`========================`);

// Return the filtered hosts as n8n items
return hostsWithInventory.map(host => ({
  json: host
}));

// Extract Specs from FOG Hosts
// Input: Array of items, each with a host object in items[i].json
// Output: Array of normalized specs for cache lookup

const results = [];

// Normalization function
function normalizeName(value) {
  if (!value || typeof value !== 'string') return 'Unknown';

  return value
    .toLowerCase()
    .replace(/^type:\s*/i, '') // Remove "Type: " prefix
    .replace(/\s*\([^)]*\)/g, '') // Remove parentheses content
    .replace(/\s+/g, ' ') // Normalize whitespace
    .trim();
}

// Process each item
for (const item of items) {
  const fogHost = item.json;

  // Check if we have inventory data
  if (!fogHost || !fogHost.inventory) {
    results.push({
      json: {
        error: 'No inventory data',
        fog_host_id: fogHost?.id || 'unknown',
        normalized_manufacturer: 'Unknown',
        normalized_model: 'Unknown',
        normalized_processor: 'Unknown',
        normalized_memory: 'Unknown',
        normalized_storage: 'Unknown',
        normalized_computer_type: 'Unknown'
      }
    });
    continue;
  }

  const inventory = fogHost.inventory;

  // Extract and normalize specs
  const normalized_manufacturer = normalizeName(inventory.sysman || 'Unknown');
  const normalized_model = normalizeName(inventory.sysproduct || 'Unknown');
  const normalized_processor = normalizeName(inventory.cpuversion || 'Unknown');
  const normalized_memory = normalizeName(inventory.memory || 'Unknown');
  const normalized_storage = normalizeName(inventory.hdmodel || 'Unknown');
  const normalized_computer_type = normalizeName(inventory.systype || 'Unknown');

  // Add to results
  results.push({
    json: {
      fog_host_id: fogHost.id,
      fog_host_name: fogHost.name,
      normalized_manufacturer,
      normalized_model,
      normalized_processor,
      normalized_memory,
      normalized_storage,
      normalized_computer_type,

      // Keep original values for reference
      original_manufacturer: inventory.sysman || 'Unknown',
      original_model: inventory.sysproduct || 'Unknown',
      original_processor: inventory.cpuversion || 'Unknown',
      original_memory: inventory.memory || 'Unknown',
      original_storage: inventory.hdmodel || 'Unknown',
      original_computer_type: inventory.systype || 'Unknown'
    }
  });
}

// Return all results
return results;

// Process ALL items in the input array
const results = [];

for (const item of items) {
  const itemData = item.json;

  // Extract FOG host specs from the item
  const fogSpecs = {
    fog_host_id: itemData.fog_host_id,
    fog_host_name: itemData.fog_host_name,
    manufacturer: itemData.original_manufacturer,
    manufacturer_normalized: itemData.normalized_manufacturer,
    model: itemData.original_model,
    model_normalized: itemData.normalized_model,
    processor: itemData.original_processor,
    processor_normalized: itemData.normalized_processor,
    memory: itemData.original_memory,
    memory_normalized: itemData.normalized_memory,
    computer_type: itemData.original_computer_type,
    computer_type_normalized: itemData.normalized_computer_type,
    storage: itemData.original_storage,
    storage_normalized: itemData.normalized_storage
  };

  // Collect cache match for this item
  const cacheMatches = [];

  // Check if we have entity_type and glpi_id at root level (from PostgreSQL query)
  if (itemData.entity_type && itemData.glpi_id && itemData.name) {
    cacheMatches.push({
      entity_type: itemData.entity_type,
      glpi_id: itemData.glpi_id,
      name: itemData.name
    });
  }

  // Group cache matches by entity_type for easy lookup
  const matchesByType = {};
  cacheMatches.forEach(match => {
    if (!matchesByType[match.entity_type]) {
      matchesByType[match.entity_type] = [];
    }
    matchesByType[match.entity_type].push(match);
  });

  // Map our entity types to GLPI itemtypes
  const glpiItemtypeMap = {
    'manufacturer': 'Manufacturer',
    'model': 'ComputerModel',
    'processor': 'DeviceProcessor',
    'memory': 'DeviceMemory',
    'computer_type': 'ComputerType',
    'storage': 'DeviceHardDrive'
  };

  // Identify missing attributes for this host
  const missingAttributes = [];

  // Check manufacturer
  if (!matchesByType['manufacturer'] || matchesByType['manufacturer'].length === 0) {
    missingAttributes.push({
      entity_type: 'manufacturer',
      glpi_itemtype: 'Manufacturer',
      name: fogSpecs.manufacturer,
      normalized_name: fogSpecs.manufacturer_normalized,
      fog_host_id: fogSpecs.fog_host_id
    });
  }

  // Check model
  if (!matchesByType['model'] || matchesByType['model'].length === 0) {
    missingAttributes.push({
      entity_type: 'model',
      glpi_itemtype: 'ComputerModel',
      name: fogSpecs.model,
      normalized_name: fogSpecs.model_normalized,
      fog_host_id: fogSpecs.fog_host_id
    });
  }

  // Check processor
  if (!matchesByType['processor'] || matchesByType['processor'].length === 0) {
    missingAttributes.push({
      entity_type: 'processor',
      glpi_itemtype: 'DeviceProcessor',
      name: fogSpecs.processor,
      normalized_name: fogSpecs.processor_normalized,
      fog_host_id: fogSpecs.fog_host_id
    });
  }

  // Check memory
  if (!matchesByType['memory'] || matchesByType['memory'].length === 0) {
    missingAttributes.push({
      entity_type: 'memory',
      glpi_itemtype: 'DeviceMemory',
      name: fogSpecs.memory,
      normalized_name: fogSpecs.memory_normalized,
      fog_host_id: fogSpecs.fog_host_id
    });
  }

  // Check computer_type
  if (!matchesByType['computer_type'] || matchesByType['computer_type'].length === 0) {
    missingAttributes.push({
      entity_type: 'computer_type',
      glpi_itemtype: 'ComputerType',
      name: fogSpecs.computer_type,
      normalized_name: fogSpecs.computer_type_normalized,
      fog_host_id: fogSpecs.fog_host_id
    });
  }

  // Check storage
  if (!matchesByType['storage'] || matchesByType['storage'].length === 0) {
    missingAttributes.push({
      entity_type: 'storage',
      glpi_itemtype: 'DeviceHardDrive',
      name: fogSpecs.storage,
      normalized_name: fogSpecs.storage_normalized,
      fog_host_id: fogSpecs.fog_host_id
    });
  }

  // Add the structured data to the output
  results.push({
    json: {
      ...itemData,
      fog_specs: fogSpecs,
      cache_matches: cacheMatches,
      cache_matches_by_type: matchesByType,
      missing_attributes: missingAttributes,
      glpi_itemtype_map: glpiItemtypeMap
    }
  });
}

return results;

// Collect unique missing attributes across all hosts
const allMissingAttributes = {
  manufacturer: new Map(), // key: normalized_name, value: {name, normalized_name, fog_host_ids[]}
  model: new Map(),
  processor: new Map(),
  memory: new Map(),
  computer_type: new Map(),
  storage: new Map()
};

// Collect all missing attributes
for (const item of items) {
  const missingAttrs = item.json.missing_attributes || [];
  const fogHostId = item.json.fog_host_id;

  for (const attr of missingAttrs) {
    const entityType = attr.entity_type;
    const normalizedName = attr.normalized_name;
    const name = attr.name;

    if (!allMissingAttributes[entityType].has(normalizedName)) {
      allMissingAttributes[entityType].set(normalizedName, {
        name: name,
        normalized_name: normalizedName,
        glpi_itemtype: attr.glpi_itemtype,
        fog_host_ids: [fogHostId]
      });
    } else {
      // Add this host to the list if not already there
      const existing = allMissingAttributes[entityType].get(normalizedName);
      if (!existing.fog_host_ids.includes(fogHostId)) {
        existing.fog_host_ids.push(fogHostId);
      }
    }
  }
}

// Convert to arrays for easier processing
const uniqueMissingAttributes = [];
for (const [entityType, map] of Object.entries(allMissingAttributes)) {
  for (const [normalizedName, data] of map.entries()) {
    uniqueMissingAttributes.push({
      entity_type: entityType,
      glpi_itemtype: data.glpi_itemtype,
      name: data.name,
      normalized_name: normalizedName,
      fog_host_ids: data.fog_host_ids,
      count: data.fog_host_ids.length
    });
  }
}

// Also collect existing cache matches for reference
const existingCacheMatches = {
  manufacturer: new Map(),
  model: new Map(),
  processor: new Map(),
  memory: new Map(),
  computer_type: new Map(),
  storage: new Map()
};

for (const item of items) {
  const cacheMatches = item.json.cache_matches || [];
  for (const match of cacheMatches) {
    const entityType = match.entity_type;
    const glpiId = match.glpi_id;
    const name = match.name;

    if (!existingCacheMatches[entityType].has(glpiId)) {
      existingCacheMatches[entityType].set(glpiId, {
        name: name,
        glpi_id: glpiId,
        entity_type: entityType
      });
    }
  }
}

// Convert existing matches to array
const existingMatchesArray = [];
for (const [entityType, map] of Object.entries(existingCacheMatches)) {
  for (const [glpiId, data] of map.entries()) {
    existingMatchesArray.push(data);
  }
}

// Return summary data
return [{
  json: {
    summary: {
      total_hosts: items.length,
      unique_missing_attributes: uniqueMissingAttributes.length,
      unique_missing_by_type: {
        manufacturer: allMissingAttributes.manufacturer.size,
        model: allMissingAttributes.model.size,
        processor: allMissingAttributes.processor.size,
        memory: allMissingAttributes.memory.size,
        computer_type: allMissingAttributes.computer_type.size,
        storage: allMissingAttributes.storage.size
      },
      existing_cache_matches: existingMatchesArray.length
    },
    unique_missing_attributes: uniqueMissingAttributes,
    existing_cache_matches: existingMatchesArray,
    all_host_data: items.map(item => ({
      fog_host_id: item.json.fog_host_id,
      fog_host_name: item.json.fog_host_name,
      missing_attributes: item.json.missing_attributes,
      cache_matches: item.json.cache_matches
    }))
  }
}];

// Get unique missing attributes
const uniqueMissingAttrs = items[0].json.unique_missing_attributes;

// Process each attribute type in batches
const batches = {
  manufacturer: uniqueMissingAttrs.filter(a => a.entity_type === 'manufacturer'),
  model: uniqueMissingAttrs.filter(a => a.entity_type === 'model'),
  processor: uniqueMissingAttrs.filter(a => a.entity_type === 'processor'),
  memory: uniqueMissingAttrs.filter(a => a.entity_type === 'memory'),
  computer_type: uniqueMissingAttrs.filter(a => a.entity_type === 'computer_type'),
  storage: uniqueMissingAttrs.filter(a => a.entity_type === 'storage')
};

// Create glpi_ids from ALL cache matches in the input
const allGlpiIds = {
  manufacturers: {},
  models: {},
  processors: {},
  memory: {},
  types: {},
  storage: {}
};

// Get cache matches from the input
const inputData = items[0].json;

// DEBUG: Show what we're working with
console.log('=== CACHE DATA DEBUG ===');
console.log('Input has existing_cache_matches?', !!inputData.existing_cache_matches);
console.log('Input has all_host_data?', !!inputData.all_host_data);

// Collect cache matches from ALL possible locations
const allCacheMatches = [];

// 1. Check existing_cache_matches (array at root level)
if (inputData.existing_cache_matches && Array.isArray(inputData.existing_cache_matches)) {
  console.log(`Found ${inputData.existing_cache_matches.length} matches in existing_cache_matches`);
  allCacheMatches.push(...inputData.existing_cache_matches);
}

// 2. Check cache_matches inside all_host_data
if (inputData.all_host_data && Array.isArray(inputData.all_host_data)) {
  let hostMatchesCount = 0;
  inputData.all_host_data.forEach(host => {
    if (host.cache_matches && Array.isArray(host.cache_matches)) {
      hostMatchesCount += host.cache_matches.length;
      allCacheMatches.push(...host.cache_matches);
    }
  });
  console.log(`Found ${hostMatchesCount} matches in all_host_data cache_matches`);
}

console.log(`Total cache matches collected: ${allCacheMatches.length}`);

// Process all collected cache matches
allCacheMatches.forEach(match => {
  if (match.glpi_id) {
    // Use normalized_name if available, otherwise normalize the name
    const idKey = match.normalized_name || (match.name ? match.name.toLowerCase() : null);

    if (!idKey) {
      console.log('Skipping cache match without name:', match);
      return;
    }

    const key = match.entity_type;

    switch(key) {
      case 'manufacturer':
        allGlpiIds.manufacturers[idKey] = match.glpi_id;
        break;
      case 'model':
        allGlpiIds.models[idKey] = match.glpi_id;
        break;
      case 'processor':
        allGlpiIds.processors[idKey] = match.glpi_id;
        break;
      case 'memory':
        allGlpiIds.memory[idKey] = match.glpi_id;
        break;
      case 'computer_type':
        allGlpiIds.types[idKey] = match.glpi_id;
        break;
      case 'storage':
        allGlpiIds.storage[idKey] = match.glpi_id;
        break;
      default:
        console.log('Unknown entity_type in cache match:', match);
    }
  }
});

console.log('=== CREATED GLPI_IDS ===');
console.log('Manufacturers:', Object.keys(allGlpiIds.manufacturers));
console.log('Models:', Object.keys(allGlpiIds.models));
console.log('Processors:', Object.keys(allGlpiIds.processors));
console.log('Memory:', Object.keys(allGlpiIds.memory));
console.log('Types:', Object.keys(allGlpiIds.types));
console.log('Storage:', Object.keys(allGlpiIds.storage));

// Return the batches for processing
return [{
  json: {
    batches: batches,
    total_to_create: uniqueMissingAttrs.length,
    summary: items[0].json.summary,
    glpi_ids: allGlpiIds
  }
}];

// We know we only created "Dell Inc."
// Hardcode the values for now since we're only creating one manufacturer
const cacheUpdates = [];

for (const item of items) {
  const response = item.json; // {id: 19, message: ...}

  // We know this is for "Dell Inc."
  cacheUpdates.push({
    json: {
      glpi_id: response.id,
      name: "Dell Inc.",
      normalized_name: "dell inc.",
      entity_type: "manufacturer"
    }
  });
}

return cacheUpdates;

const manufacturers = items[0].json.batches.manufacturer;
console.log(`Manufacturers to create: ${manufacturers.length}`);

return manufacturers.map(mfg => ({
  json: {
    ...mfg,
    original_data: {
      name: mfg.name,
      normalized_name: mfg.normalized_name,
      entity_type: mfg.entity_type
    },
    api_request_data: {
      name: mfg.name,
      comment: "Created from FOG import"
    },
    glpi_endpoint: "Manufacturer"
  }
}));

const computerTypes = items[0].json.batches.computer_type;
console.log(`Computer types to create: ${computerTypes.length}`);

return computerTypes.map(ct => {
  let normalizedName = ct.normalized_name;
  if (ct.name === "Type: Notebook") normalizedName = "notebook";
  if (ct.name === "Type: Desktop") normalizedName = "desktop";

  return {
    json: {
      ...ct,
      original_data: {
        name: ct.name,
        normalized_name: normalizedName,
        entity_type: ct.entity_type
      },
      api_request_data: {
        name: ct.name,
        comment: "Created from FOG import"
      },
      glpi_endpoint: "ComputerType"
    }
  };
});

// Process all computer type creation responses
const cacheUpdates = [];

for (const item of items) {
  const response = item.json; // {id: X, message: "Item successfully added: Type: Notebook"}
  const originalData = item.json.original_data; // Get original data we preserved

  // Extract computer type name from response message
  // Format: "Item successfully added: Type: Notebook"
  const message = response.message || "";
  let computerTypeName = originalData ? originalData.name : "Unknown";

  if (message.includes(":")) {
    // Extract from message: "Item successfully added: Type: Notebook"
    const parts = message.split(": ");
    if (parts.length > 1) {
      computerTypeName = parts.slice(1).join(": ").trim();
    }
  }

  // Determine normalized name
  let normalizedName = computerTypeName.toLowerCase();

  // Clean up normalized name (remove "type: " prefix if present)
  if (normalizedName.startsWith("type: ")) {
    normalizedName = normalizedName.substring(6); // Remove "type: "
  }

  // Special handling for common computer types
  if (computerTypeName === "Type: Notebook" || computerTypeName === "Notebook") {
    normalizedName = "notebook";
  } else if (computerTypeName === "Type: Desktop" || computerTypeName === "Desktop") {
    normalizedName = "desktop";
  }

  cacheUpdates.push({
    json: {
      glpi_id: response.id,
      name: computerTypeName,
      normalized_name: normalizedName,
      entity_type: "computer_type"
    }
  });
}

// Log summary
console.log(`Processed ${cacheUpdates.length} computer types for cache`);
cacheUpdates.forEach((update, index) => {
  console.log(`${index + 1}. ${update.json.name} → GLPI ID: ${update.json.glpi_id}, Normalized: ${update.json.normalized_name}`);
});

return cacheUpdates;

const models = items[0].json.batches.model;
console.log(`Models to create: ${models.length}`);

return models.map(model => {
  const normalized = model.normalized_name || model.name.toLowerCase();
  let manufacturerId = 19; // Default to Dell

  if (normalized.includes('hp') || normalized.includes('elitebook') || normalized.includes('probook')) {
    manufacturerId = 6;
  } else if (normalized.includes('fujitsu') || normalized.includes('esprimo') || normalized.includes('lifebook')) {
    manufacturerId = 8;
  }

  return {
    json: {
      ...model,
      original_data: {
        name: model.name,
        normalized_name: model.normalized_name,
        entity_type: model.entity_type,
        manufacturer_id: manufacturerId
      },
      api_request_data: {
        name: model.name,
        product_number: model.normalized_name,
        comment: "Created from FOG import",
        manufacturers_id: manufacturerId
      },
      glpi_endpoint: "ComputerModel"
    }
  };
});

// Process all computer model creation responses
const cacheUpdates = [];

for (const item of items) {
  const response = item.json; // {id: X, message: "Item successfully added: Latitude 3520"}
  const originalData = item.json.original_data; // Get original data we preserved

  // Extract model name from response message
  // Format: "Item successfully added: Latitude 3520"
  const message = response.message || "";
  let modelName = originalData ? originalData.name : "Unknown Model";

  if (message.includes(":")) {
    // Extract from message: "Item successfully added: Latitude 3520"
    const parts = message.split(": ");
    if (parts.length > 1) {
      modelName = parts.slice(1).join(": ").trim();
    }
  }

  // Get normalized name from original data or generate it
  let normalizedName = originalData ? originalData.normalized_name : modelName.toLowerCase();

  // Get manufacturer ID from original data
  const manufacturerId = originalData ? originalData.manufacturer_id : null;

  cacheUpdates.push({
    json: {
      glpi_id: response.id,
      name: modelName,
      normalized_name: normalizedName,
      entity_type: "model",
      manufacturer_id: manufacturerId  // Optional: store manufacturer ID in cache
    }
  });
}

// Log summary
console.log(`\n=== COMPUTER MODEL CACHE UPDATE SUMMARY ===`);
console.log(`Total models processed: ${cacheUpdates.length}`);
console.log(`Models to cache:`);
cacheUpdates.forEach((update, index) => {
  const manufacturerInfo = update.json.manufacturer_id ? `, Manufacturer ID: ${update.json.manufacturer_id}` : '';
  console.log(`${index + 1}. ${update.json.name} → GLPI ID: ${update.json.glpi_id}${manufacturerInfo}`);
});

return cacheUpdates;

// Process all processor creation responses for cache updates
const cacheUpdates = [];

for (const item of items) {
  const response = item.json; // GLPI response: {id: X, message: "Item successfully added: ..."}

  // Try to get original data from different possible locations
  let originalData = item.json.original_data;
  let processorName = "Unknown Processor";
  let normalizedName = "unknown";
  let entityType = "processor";

  // If original_data exists, use it
  if (originalData && originalData.name) {
    processorName = originalData.name;
    normalizedName = originalData.normalized_name || processorName.toLowerCase();
    entityType = originalData.entity_type || "processor";
  } 
  // Otherwise try to extract from response message
  else {
    const message = response.message || "";
    if (message.includes(":")) {
      // Extract from message: "Item successfully added: Processor Name"
      const parts = message.split(": ");
      if (parts.length > 1) {
        processorName = parts.slice(1).join(": ").trim();
        normalizedName = processorName.toLowerCase();
      }
    }
    // Fallback to any available name field
    else if (item.json.name) {
      processorName = item.json.name;
      normalizedName = item.json.normalized_name || processorName.toLowerCase();
    }
  }

  // Clean up the name if it's "N/A"
  if (processorName === "N/A" && originalData && originalData.name) {
    processorName = originalData.name;
    normalizedName = originalData.normalized_name || processorName.toLowerCase();
  }

  cacheUpdates.push({
    json: {
      glpi_id: response.id,
      name: processorName,
      normalized_name: normalizedName,
      entity_type: entityType
    }
  });
}

// Log summary
console.log(`\n=== PROCESSOR CACHE UPDATE SUMMARY ===`);
console.log(`Total processors cached: ${cacheUpdates.length}`);
cacheUpdates.forEach((update, index) => {
  console.log(`${index + 1}. ${update.json.name} → GLPI ID: ${update.json.glpi_id}`);
});

return cacheUpdates;

const processors = items[0].json.batches.processor || [];
console.log(`Processors to create: ${processors.length}`);

// If no processors, return empty array in n8n format
if (processors.length === 0) {
  console.log('No processors to create - returning empty array in n8n format');
  // Return empty array wrapped in n8n format
  return [{ json: { message: "No processors to create", processors: [] } }];
}

const processorItems = processors.map(proc => {
  const name = proc.name || '';
  let frequency = 0;
  const freqMatch = name.match(/(\d+\.\d+)GHz/i);
  if (freqMatch) {
    frequency = parseFloat(freqMatch[1]) * 1000;
  }

  let nbcores = 4;
  if (name.includes('i3')) nbcores = 2;
  else if (name.includes('i5')) nbcores = 4;
  else if (name.includes('i7') || name.includes('i9')) nbcores = 8;
  else if (name.includes('Ryzen 3')) nbcores = 4;
  else if (name.includes('Ryzen 5')) nbcores = 6;
  else if (name.includes('Ryzen 7')) nbcores = 8;

  return {
    json: {
      ...proc,
      original_data: {
        name: proc.name,
        normalized_name: proc.normalized_name,
        entity_type: proc.entity_type,
        frequency: frequency,
        nbcores: nbcores
      },
      api_request_data: {
        designation: proc.name,
        comment: "Created from FOG import",
        frequency: frequency,
        nbcores: nbcores
      },
      glpi_endpoint: "DeviceProcessor"
    }
  };
});

console.log(`Created ${processorItems.length} processor items`);
return processorItems;

const memory = items[0].json.batches.memory;
console.log(`Memory items to create: ${memory.length}`);

return memory.map(mem => {
  const name = mem.name || '';
  let size = 0;
  const sizeMatch = name.match(/(\d+\.?\d*)\s*(GiB|GB|MB)/i);
  if (sizeMatch) {
    size = parseFloat(sizeMatch[1]);
    if (sizeMatch[2].toUpperCase() === 'GB' || sizeMatch[2].toUpperCase() === 'GIB') {
      size = size * 1024; // Convert to MB
    }
  }

  return {
    json: {
      ...mem,
      original_data: {
        name: mem.name,
        normalized_name: mem.normalized_name,
        entity_type: mem.entity_type,
        size: Math.round(size)
      },
      api_request_data: {
        designation: mem.name,
        comment: "Created from FOG import",
        size: Math.round(size)
      },
      glpi_endpoint: "DeviceMemory"
    }
  };
});

const storage = items[0].json.batches.storage;
console.log(`Storage items to create: ${storage.length}`);

return storage.map(storageItem => {
  const name = storageItem.name || '';
  let capacity = 0;

  console.log(`\nProcessing storage: "${name}"`);

  // SPECIAL CASES FIRST

  // Special case: Micron drive with "256" in model number
  if (name.includes('MTFDDAK256TBN')) {
    capacity = 256 * 1024; // 256GB
    console.log(`  Special case: MTFDDAK256TBN → 256GB → ${capacity}MB`);
  }
  // Special case: "DT01ACA100" is actually 1TB (1000GB)
  else if (name.includes('DT01ACA100')) {
    capacity = 1000 * 1024; // 1TB = 1000GB × 1024 = 1,024,000 MB
    console.log(`  Special case: DT01ACA100 → 1TB → ${capacity}MB`);
  }
  // Special case: "Unknown" storage
  else if (name === 'Unknown') {
    capacity = 0; // Keep as 0
    console.log(`  Special case: Unknown → 0MB`);
  }
  // REGULAR PATTERN MATCHING (only if no special case matched)
  else {
    // Pattern 1: Look for "256GB", "512GB", "128GB" format
    const gbPattern = name.match(/(\d{3,4})\s*GB/i);
    if (gbPattern) {
      capacity = parseInt(gbPattern[1]) * 1024; // GB to MB
      console.log(`  Pattern 1 (GB): ${gbPattern[1]}GB → ${capacity}MB`);
    }

    // Pattern 2: Look for "256G" (without B) in model codes
    if (capacity === 0) {
      const gPattern = name.match(/(\d{3,4})G(?!B)/i); // 256G but not 256GB
      if (gPattern) {
        capacity = parseInt(gPattern[1]) * 1024;
        console.log(`  Pattern 2 (G): ${gPattern[1]}G → ${capacity}MB`);
      }
    }

    // Pattern 3: Look for standalone numbers with word boundaries
    if (capacity === 0) {
      const patterns = [
        { pattern: /\b256G\b/i, capacity: 256 },
        { pattern: /\b512G\b/i, capacity: 512 },
        { pattern: /\b128G\b/i, capacity: 128 },
        { pattern: /\b256GB\b/i, capacity: 256 },
        { pattern: /\b512GB\b/i, capacity: 512 },
        { pattern: /\b128GB\b/i, capacity: 128 },
        { pattern: /\b100GB\b/i, capacity: 100 },
        { pattern: /\b256\b/, capacity: 256 }, // Standalone 256
        { pattern: /\b512\b/, capacity: 512 }, // Standalone 512
        { pattern: /\b128\b/, capacity: 128 }, // Standalone 128
        { pattern: /\b100\b/, capacity: 100 }, // Standalone 100
      ];

      for (const { pattern, capacity: capGB } of patterns) {
        if (pattern.test(name)) {
          capacity = capGB * 1024;
          console.log(`  Pattern 3 (word boundary): ${capGB}GB → ${capacity}MB`);
          break;
        }
      }
    }
  }

  if (capacity === 0) {
    console.log(`  WARNING: Could not extract capacity from: "${name}"`);
  } else {
    console.log(`  Final capacity: ${capacity}MB`);
  }

  // Determine interface type
  let interfaceType = 0; // 0 = unknown
  if (name.includes('NVMe') || name.includes('M.2') || /NVMe/i.test(name)) {
    interfaceType = 1; // NVMe
  } else if (name.includes('SATA')) {
    interfaceType = 2; // SATA
  }

  // Determine manufacturer based on model name
  let manufacturerId = 0; // Unknown
  if (name.includes('SAMSUNG') || name.includes('Samsung')) {
    manufacturerId = 1; // Samsung
  } else if (name.includes('TOSHIBA') || name.includes('Toshiba')) {
    manufacturerId = 2; // Toshiba
  } else if (name.includes('KIOXIA')) {
    manufacturerId = 3; // Kioxia
  } else if (name.includes('SKhynix') || name.includes('SK Hynix')) {
    manufacturerId = 4; // SK Hynix
  } else if (name.includes('WD') || name.includes('Western Digital')) {
    manufacturerId = 5; // Western Digital
  } else if (name.includes('Micron')) {
    manufacturerId = 6; // Micron
  } else if (name.includes('LITEON')) {
    manufacturerId = 7; // Lite-On
  }

  return {
    json: {
      ...storageItem,
      original_data: {
        name: storageItem.name,
        normalized_name: storageItem.normalized_name,
        entity_type: storageItem.entity_type,
        capacity: capacity,
        interface_type: interfaceType,
        manufacturer_id: manufacturerId
      },
      api_request_data: {
        designation: storageItem.name,
        comment: "Created from FOG import",
        capacity_default: capacity,
        interfacetypes_id: interfaceType,
        manufacturers_id: manufacturerId
      },
      glpi_endpoint: "DeviceHardDrive"
    }
  };
});

// Process all memory creation responses for cache updates
const cacheUpdates = [];

for (const item of items) {
  const response = item.json; // GLPI response: {id: X, message: "Item successfully added: ..."}

  // Try to get original data from different possible locations
  let originalData = item.json.original_data;
  let memoryName = "Unknown Memory";
  let normalizedName = "unknown";
  let entityType = "memory";
  let size = 0;

  // If original_data exists, use it
  if (originalData) {
    memoryName = originalData.name || memoryName;
    normalizedName = originalData.normalized_name || memoryName.toLowerCase();
    entityType = originalData.entity_type || "memory";
    size = originalData.size || 0;
  } 
  // Otherwise try to extract from response message
  else {
    const message = response.message || "";
    if (message.includes(":")) {
      // Extract from message: "Item successfully added: Memory Name"
      const parts = message.split(": ");
      if (parts.length > 1) {
        memoryName = parts.slice(1).join(": ").trim();
        normalizedName = memoryName.toLowerCase();
      }
    }
    // Fallback to any available name field
    else if (item.json.name) {
      memoryName = item.json.name;
      normalizedName = item.json.normalized_name || memoryName.toLowerCase();
    }
  }

  // Clean up the name if it's "N/A"
  if (memoryName === "N/A" && originalData && originalData.name) {
    memoryName = originalData.name;
    normalizedName = originalData.normalized_name || memoryName.toLowerCase();
  }

  cacheUpdates.push({
    json: {
      glpi_id: response.id,
      name: memoryName,
      normalized_name: normalizedName,
      entity_type: entityType,
      size: size  // Optional: store size in cache if needed
    }
  });
}

// Log summary
console.log(`\n=== MEMORY CACHE UPDATE SUMMARY ===`);
console.log(`Total memory items cached: ${cacheUpdates.length}`);
cacheUpdates.forEach((update, index) => {
  const sizeInfo = update.json.size ? ` (${update.json.size}MB)` : '';
  console.log(`${index + 1}. ${update.json.name}${sizeInfo} → GLPI ID: ${update.json.glpi_id}`);
});

return cacheUpdates;

